parameters.jsCode:
// Colmeia Modo Mewtwo Result Aggregator
const bielData = $('Biel Strategic Analysis').first().json;
const brunoData = $('Bruno Documentation').first().json;
const martinhoData = $('Martinho Security Audit').first().json;
const hamiltonData = $('Hamilton Resilience Check').first().json;
const safepointData = $('SafePoint Backup').first().json;

// Aggregate results
const result = {
  sessionId: `mewtwo_${Date.now()}`,
  timestamp: new Date().toISOString(),
  mode: 'mewtwo',
  status: 'completed',

  // Agent summaries
  agents: {
    biel: {
      summary: bielData.summary || bielData.result,
      insights: bielData.insights || [],
      recommendations: bielData.recommendations || []
    },
    bruno: {
      documentation: brunoData.notionPages || brunoData.document,
      kanban: brunoData.kanbanUpdate || null,
      organization: brunoData.organizationalSummary || brunoData.result
    },
    martinho: {
      security: martinhoData.securityAudit || martinhoData.execution,
      compliance: martinhoData.complianceStatus,
      score: martinhoData.securityAudit?.score || 0
    },
    hamilton: {
      resilience: hamiltonData.resilienceReport || hamiltonData.result,
      metrics: hamiltonData.metrics || {},
      diversity: hamiltonData.diversityIndex || 'unknown'
    }
  },

  // SafePoint results
  backup: {
    id: safepointData.backupManifest?.id,
    status: safepointData.backupManifest?.status,
    size: safepointData.totalSize,
    files: safepointData.files?.length || 0,
    verification: safepointData.verificationStatus
  },

  // Overall assessment
  assessment: {
    securityScore: martinhoData.securityAudit?.score || 0,
    resilienceLevel: hamiltonData.resilienceReport?.systemHealth || 'unknown',
    backupStatus: safepointData.backupManifest?.status || 'unknown',
    overallHealth: 'optimal' // This would be calculated based on all factors
  },

  // Human oversight controls
  controls: {
    killSwitchAvailable: true,
    humanConfirmationRequired: false,
    reversible: true,
    auditTrail: true
  },

  // Next actions
  nextActions: [
    'Review agent recommendations',
    'Confirm backup integrity',
    'Monitor system metrics',
    'Schedule next automation cycle'
  ]
};

return [{ json: result }];

